#include "light_sleep.h"
#include <esp_sleep.h>
void light_sleep_setup(){Serial.println("[lsleep] OK");}
void light_sleep_for(uint32_t ms){esp_sleep_enable_timer_wakeup(ms*1000ULL);esp_light_sleep_start();Serial.printf("[lsleep] Woke after %ldms\n",(long)ms);}
void light_sleep_until_pin(uint8_t pin,bool level){gpio_wakeup_enable((gpio_num_t)pin,level?GPIO_INTR_HIGH_LEVEL:GPIO_INTR_LOW_LEVEL);esp_sleep_enable_gpio_wakeup();esp_light_sleep_start();}
uint32_t light_sleep_wakeup_cause(){return esp_sleep_get_wakeup_cause();}
